    progress
        .folder_total
        .map(|total| total as u64)
        .or_else(|| scanner_percent_as_count(progress.percent).map(|_| 100))
}

fn scanner_percent_as_count(percent: f32) -> Option<u64> {
    if percent.is_finite() {
        Some(percent.clamp(0.0, 100.0).round() as u64)
    } else {
        None
    }
}

