fn trace_scanner_scan_output(output: &ScannerScanOutput) {
    tracing::info!(
        event = "s07-scanner-scan-output",
        scan_id = output.scan_id,
        status = ?output.status.kind,
        result_count = output.results.len(),
        group_count = output.groups.len(),
